#include <stdio.h>

int main(void)
{
    int i, nz, no, n, x;
    scanf("%d\n", &n);

    nz = no = 0;

    for (i = 0; i < n; i++) {
        x = getchar();
        if (x == '1') {
            no++;
        } else if (x == '0') {
            nz++;
        }
    }

    if (no >= 1) {
        printf("1");

        for (i = 0; i < nz; i++) {
            printf("0");
        }
    } else {
        printf("0");
    }

    return 0;
}

